```rust
use serde::{Deserialize, Serialize};
use serde_json::value::RawValue;
use std::sync::Arc;

/// Core metadata fields - always parsed immediately
#[derive(Debug, Clone, Deserialize)]
pub struct CoreMetadata {
    pub source_path: String,
    pub agent_type: String,
    pub timestamp: i64,
    pub line_number: Option<u32>,
}

/// Full metadata with lazy parsing for expensive fields
#[derive(Debug)]
pub struct LazyMetadata {
    /// Core fields parsed immediately
    pub core: CoreMetadata,
    /// Raw JSON for deferred parsing
    raw_json: Arc<str>,
    /// Cached full parse (populated on first access)
    full_cache: OnceCell<FullMetadata>,
}

impl LazyMetadata {
    /// Parse from JSON string
    pub fn from_json(json: &str) -> Result<Self, serde_json::Error> {
        let core: CoreMetadata = serde_json::from_str(json)?;
        Ok(Self {
            core,
            raw_json: Arc::from(json),
            full_cache: OnceCell::new(),
        })
    }

    /// Get full metadata (parses on first call, cached thereafter)
    pub fn full(&self) -> Result<&FullMetadata, serde_json::Error> {
        self.full_cache.get_or_try_init(|| {
            serde_json::from_str(&self.raw_json)
        })
    }

    /// Check if full metadata has been accessed
    pub fn is_full_loaded(&self) -> bool {
        self.full_cache.get().is_some()
    }
}

/// Complete metadata structure
#[derive(Debug, Clone, Deserialize)]
pub struct FullMetadata {
    // Include all fields
    pub source_path: String,
    pub agent_type: String,
    pub timestamp: i64,
    pub line_number: Option<u32>,
    pub content: Option<String>,
    pub tool_calls: Option<Vec<ToolCall>>,
    pub token_count: Option<u32>,
    pub model: Option<String>,
    // ... all other fields
}
```

