        "model": "claude-3-opus"
    }"#;

    #[test]
    fn test_lazy_parse_core_only() {
        let meta = LazyMetadata::from_json(TEST_JSON).unwrap();

        // Core fields immediately available
        assert_eq!(meta.core.source_path, "/home/user/.claude/projects/test/session.jsonl");
        assert_eq!(meta.core.agent_type, "claude");
        assert_eq!(meta.core.timestamp, 1704067200);
        assert_eq!(meta.core.line_number, Some(42));

        // Full parse not yet triggered
        assert!(!meta.is_full_loaded());
    }

    #[test]
    fn test_lazy_parse_full_on_demand() {
        let meta = LazyMetadata::from_json(TEST_JSON).unwrap();

        // Access full metadata
        let full = meta.full().unwrap();
        assert_eq!(full.token_count, Some(1234));
        assert_eq!(full.model, Some("claude-3-opus".to_string()));

        // Now cached
        assert!(meta.is_full_loaded());

        // Second access uses cache (doesn't re-parse)
        let full2 = meta.full().unwrap();
        assert_eq!(full.token_count, full2.token_count);
    }

    #[test]
    fn test_malformed_core_fields() {
        let bad_json = r#"{"agent_type": "claude"}"#; // Missing source_path
        let result = LazyMetadata::from_json(bad_json);
        assert!(result.is_err());
    }

    #[test]
    fn test_malformed_lazy_fields() {
        // Core valid, but full parse would fail
        let partial_json = r#"{
            "source_path": "/test",
            "agent_type": "claude", 
            "timestamp": 123,
            "tool_calls": "not_an_array"
        }"#;

        let meta = LazyMetadata::from_json(partial_json).unwrap();
        assert_eq!(meta.core.source_path, "/test");

        // Full parse fails gracefully
        let full_result = meta.full();
        assert!(full_result.is_err());
    }

    #[test]
    fn test_thread_safety() {
        use std::sync::Arc;
        use std::thread;

        let meta = Arc::new(LazyMetadata::from_json(TEST_JSON).unwrap());
        let mut handles = vec![];

        for _ in 0..10 {
            let meta_clone = Arc::clone(&meta);
            handles.push(thread::spawn(move || {
                let full = meta_clone.full().unwrap();
                assert_eq!(full.agent_type, "claude");
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }
    }
}
