#[test]
fn test_tui_scroll_performance_with_lazy_parse() {
    // Create large test dataset
    let temp_dir = setup_test_index_with_sessions(1000);

    // Simulate TUI scroll (rapid sequential access to list view)
    let mut total_core_parses = 0;
    let mut total_full_parses = 0;

    for page in 0..50 {
        let results = search_page(&temp_dir, "query", page, 20);

        for result in &results {
            total_core_parses += 1;
            if result.metadata.is_full_loaded() {
                total_full_parses += 1;
            }
        }
    }

    // Verify lazy parsing effectiveness
    let lazy_ratio = 1.0 - (total_full_parses as f64 / total_core_parses as f64);
    println!("Lazy parse ratio: {:.1}%", lazy_ratio * 100.0);
    assert!(lazy_ratio > 0.9, "Expected >90% lazy parsing in scroll, got {:.1}%", lazy_ratio * 100.0);
}
