fn benchmark_metadata_parsing(c: &mut Criterion) {
    let test_json = generate_realistic_metadata_json();

    let mut group = c.benchmark_group("metadata_parsing");

    group.bench_function("full_parse_always", |b| {
        b.iter(|| {
            let _: FullMetadata = serde_json::from_str(&test_json).unwrap();
        })
    });

    group.bench_function("lazy_core_only", |b| {
        b.iter(|| {
            let meta = LazyMetadata::from_json(&test_json).unwrap();
            // Only access core fields
            let _ = meta.core.source_path.len();
            let _ = meta.core.timestamp;
        })
    });

    group.bench_function("lazy_then_full", |b| {
        b.iter(|| {
            let meta = LazyMetadata::from_json(&test_json).unwrap();
            let _ = meta.core.source_path.len();
            let _ = meta.full().unwrap();
        })
    });

    group.finish();
}
