## Logging & Observability
```rust
use std::sync::atomic::{AtomicU64, Ordering};
use tracing::{debug, instrument};

static CORE_PARSES: AtomicU64 = AtomicU64::new(0);
static FULL_PARSES: AtomicU64 = AtomicU64::new(0);

impl LazyMetadata {
    #[instrument(skip(json), fields(json_len = json.len()))]
    pub fn from_json(json: &str) -> Result<Self, serde_json::Error> {
        CORE_PARSES.fetch_add(1, Ordering::Relaxed);
        // ... implementation
    }

    pub fn full(&self) -> Result<&FullMetadata, serde_json::Error> {
        if self.full_cache.get().is_none() {
            FULL_PARSES.fetch_add(1, Ordering::Relaxed);
            debug!(target: "cass::perf::lazy_metadata", "Triggering full parse");
        }
        // ... implementation
    }
}

pub fn log_metadata_parse_stats() {
    let core = CORE_PARSES.load(Ordering::Relaxed);
    let full = FULL_PARSES.load(Ordering::Relaxed);
    let lazy_ratio = if core > 0 { 1.0 - (full as f64 / core as f64) } else { 0.0 };

    tracing::info!(
        target: "cass::perf::lazy_metadata",
        core_parses = core,
        full_parses = full,
        lazy_ratio = format!("{:.1}%", lazy_ratio * 100.0),
        "Metadata parsing statistics"
    );
}
```

