            parallelism: 4,  // Use all lanes
            mode: 'wasm-mt', // Multi-threaded WASM
        };
    } else {
        return {
            parallelism: 1,  // Single-threaded fallback
            mode: 'wasm-st', // Single-threaded WASM
        };
    }
}

